def insert_user(**kw) -> bool:
    """Insert user; return False on UNIQUE violation (duplicate email/username).
    DB-level UNIQUE resolves concurrent-signup races atomically; parameterized
    values prevent SQL injection. Does NOT report WHICH field collided."""
