# --------------------------------------------------------------------------- #
# Rate limiting (in-process sliding window keyed by client IP)
# --------------------------------------------------------------------------- #

class RateLimiter:
    def __init__(self, max_hits: int, window: float):
        self.max_hits, self.window = max_hits, window
        self._hits: dict[str, list[float]] = {}
        self._lock = threading.Lock()

    def allow(self, key: str, now: float) -> bool:
        with self._lock:
            bucket = self._hits.setdefault(key, [])
            cutoff = now - self.window
            bucket[:] = [t for t in bucket if t > cutoff]
            if len(bucket) >= self.max_hits:
                return False
            bucket.append(now)
            return True


_rate_limiter = RateLimiter(RATE_LIMIT_MAX, RATE_LIMIT_WINDOW)


def _client_ip(request: Request) -> str:
    fwd = request.headers.get("x-forwarded-for")  # trust only behind a known proxy
    if fwd:
        return fwd.split(",")[0].strip()
    return request.client.host if request.client else "unknown"


# --------------------------------------------------------------------------- #
# Normalization helpers
# --------------------------------------------------------------------------- #

def _strip_controls(s: str) -> str:
    """Drop control (Cc) and format (Cf: zero-width, bidi RLO/LRO) chars."""
    return "".join(c for c in s if unicodedata.category(c) not in ("Cc", "Cf"))

def _nfc(s: str) -> str:
    return unicodedata.normalize("NFC", s)

def _collapse_ws(s: str) -> str:
    return re.sub(r"\s+", " ", s).strip()

def _char_script(ch: str) -> str:
    return (unicodedata.name(ch, "") or "COMMON").split(" ")[0]


# --------------------------------------------------------------------------- #
# Error accumulator — collect ALL failures
# --------------------------------------------------------------------------- #

@dataclass
class FieldErrors:
    errors: dict[str, list[str]] = field(default_factory=dict)

    def add(self, f: str, m: str) -> None:
        self.errors.setdefault(f, []).append(m)

    def __bool__(self) -> bool:
        return bool(self.errors)

    def as_list(self) -> list[dict]:
        return [{"field": f, "message": m}
                for f, ms in self.errors.items() for m in ms]


# --------------------------------------------------------------------------- #
# Field validators
# --------------------------------------------------------------------------- #

def validate_email_field(raw, errs) -> Optional[tuple[str, str]]:
    if not isinstance(raw, str):
        errs.add("email", "Email must be a string."); return None
    value = _strip_controls(raw).strip()
    if not value:
        errs.add("email", "Email is required."); return None
    if len(value) > 254:  # RFC 5321
        errs.add("email", "Email is too long (max 254 characters)."); return None

    if _HAVE_EMAIL_VALIDATOR:
        try:
            info = validate_email(value, check_deliverability=False)
            normalized, domain, local = info.normalized, info.domain.lower(), info.local_part
        except EmailNotValidError as e:
            errs.add("email", f"Invalid email address: {e}"); return None
    else:
        if not re.match(r"^[^@\s]+@[^@\s]+\.[^@\s]+$", value):
            errs.add("email", "Invalid email address format."); return None
        local, _, domain = value.rpartition("@"); domain = domain.lower()
        normalized = f"{local}@{domain}"

    if domain in DISPOSABLE_DOMAINS:
        errs.add("email", "Disposable email addresses are not allowed."); return None

    # Canonical form for uniqueness (gmail dot/+tag folding).
    canon_local = local.lower()
    if domain in ("gmail.com", "googlemail.com"):
        canon_local = canon_local.split("+", 1)[0].replace(".", "")
    else:
        canon_local = canon_local.split("+", 1)[0]
    return normalized, f"{canon_local}@{domain}"


def validate_username_field(raw, errs) -> Optional[tuple[str, str]]:
    if not isinstance(raw, str):
        errs.add("username", "Username must be a string."); return None
    value = _nfc(_strip_controls(raw)).strip()
    if not value:
        errs.add("username", "Username is required."); return None

    if len(value) < USERNAME_MIN:
        errs.add("username", f"Username must be at least {USERNAME_MIN} characters.")
    if len(value) > USERNAME_MAX:
        errs.add("username", f"Username must be at most {USERNAME_MAX} characters.")
    if not USERNAME_RE.match(value):
        errs.add("username", "Username may contain only letters, digits, '.', '_', "
                 "'-', and must start and end with a letter or digit.")
    if ".." in value or "__" in value or "--" in value:
        errs.add("username", "Username may not contain repeated separators.")

    lower = value.lower()
    if lower in RESERVED_USERNAMES:
        errs.add("username", "This username is reserved.")
    folded = lower.translate(_HOMOGLYPH_MAP)
    if folded != lower and folded in RESERVED_USERNAMES:
        errs.add("username", "Username too closely resembles a reserved name.")
    if any(frag in lower or frag in folded for frag in OFFENSIVE_FRAGMENTS):
        errs.add("username", "Username contains disallowed content.")

    scripts = {_char_script(c) for c in value if c.isalpha()}
    scripts.discard("COMMON")
    if len(scripts) > 1:
        errs.add("username", "Username mixes multiple scripts, which is not allowed.")

    if errs.errors.get("username"):
        return None
    return value, lower


def validate_display_name_field(raw, errs) -> Optional[str]:
    if raw is None or raw == "":
        return ""  # optional → defaults to username later
    if not isinstance(raw, str):
        errs.add("display_name", "Display name must be a string."); return None
    value = _collapse_ws(_nfc(_strip_controls(raw)))
    if len(value) > DISPLAY_NAME_MAX:
        errs.add("display_name", f"Display name must be at most {DISPLAY_NAME_MAX} characters.")
        return None
    # Stored raw; XSS is prevented at OUTPUT time by context-aware encoding,
    # not by escaping on input (which corrupts data and double-encodes).
    return value


def validate_password_field(raw, *, username, email, errs) -> Optional[str]:
    if not isinstance(raw, str):
        errs.add("password", "Password must be a string."); return None
    if len(raw) > PASSWORD_MAX:  # DoS guard before any heavy work
        errs.add("password", f"Password must be at most {PASSWORD_MAX} characters.")
        return None

    if raw != raw.strip():
        errs.add("password", "Password must not start or end with whitespace.")
    if any(unicodedata.category(c) in ("Cc", "Cf") for c in raw):
        errs.add("password", "Password contains invalid control characters.")
    if len(raw) < PASSWORD_MIN:
        errs.add("password", f"Password must be at least {PASSWORD_MIN} characters.")
    if not re.search(r"[a-z]", raw):
        errs.add("password", "Password must include a lowercase letter.")
    if not re.search(r"[A-Z]", raw):
        errs.add("password", "Password must include an uppercase letter.")
    if not re.search(r"\d", raw):
        errs.add("password", "Password must include a digit.")
    if not re.search(r"[^\w\s]", raw):
        errs.add("password", "Password must include a symbol.")

    low = raw.lower()
    if low in COMMON_PASSWORDS:
        errs.add("password", "This password is too common.")
    if _has_breached_password(raw):
        errs.add("password", "This password has appeared in a known data breach.")
    if username and username.lower() in low:
        errs.add("password", "Password must not contain your username.")
    if email:
        local = email.split("@", 1)[0].lower()
        if local and local in low:
            errs.add("password", "Password must not contain your email address.")
    if re.search(r"(.)\1{3,}", raw):
        errs.add("password", "Password must not contain 4+ repeated characters.")
    if _has_sequential_run(low, 4):
        errs.add("password", "Password must not contain long sequential runs (e.g. '1234').")

    if errs.errors.get("password"):
        return None
    return raw


def _has_sequential_run(s: str, length: int) -> bool:
    run = 1
    for i in range(1, len(s)):
        if ord(s[i]) - ord(s[i - 1]) == 1:
            run += 1
            if run >= length:
                return True
        else:
            run = 1
    return False


