    """Placeholder for HaveIBeenPwned k-anonymity check:
        sha1 = hashlib.sha1(password.encode()).hexdigest().upper()
        GET https://api.pwnedpasswords.com/range/{sha1[:5]}
        return sha1[5:] in response
    SHA-1 used ONLY as a breach-lookup index here, never for storage."""
    return False


