class RegisterRequest(BaseModel):
    email: str = Field(default="", max_length=320)
    username: str = Field(default="", max_length=64)
    password: str = Field(default="", max_length=512)  # hard structural cap
    display_name: str = Field(default="", max_length=256)
    model_config = {"extra": "forbid"}  # reject unexpected fields


# --------------------------------------------------------------------------- #
# Application
# --------------------------------------------------------------------------- #

app = FastAPI(title="Registration API")


@app.on_event("startup")
def _startup() -> None:
    init_db()


# Neutral response used for BOTH "created" and "already exists" → no enumeration.
_NEUTRAL_SUCCESS = {
    "status": "ok",
    "message": ("If the information provided is valid and not already in use, "
                "your account has been created. Please check your email to continue."),
}


@app.post("/api/register")
async def register(request: Request):
    now = time.monotonic()

    # 1) Rate limit before any expensive work.
    ip = _client_ip(request)
    if not _rate_limiter.allow(ip, now):
        return JSONResponse(
            status_code=status.HTTP_429_TOO_MANY_REQUESTS,
            headers={"Retry-After": str(int(RATE_LIMIT_WINDOW))},
            content={"status": "error",
                     "message": "Too many registration attempts. Please try again later."},
        )

    # 2) Parse body defensively.
    try:
        payload = await request.json()
    except Exception:
        return JSONResponse(status_code=status.HTTP_400_BAD_REQUEST,
            content={"status": "error", "message": "Request body must be valid JSON."})
    if not isinstance(payload, dict):
        return JSONResponse(status_code=status.HTTP_400_BAD_REQUEST,
            content={"status": "error", "message": "Request body must be a JSON object."})

    # 3) Structural validation.
    try:
        req = RegisterRequest(**payload)
    except Exception as e:
        return JSONResponse(status_code=status.HTTP_422_UNPROCESSABLE_ENTITY,
            content={"status": "error", "message": "Malformed request.", "detail": str(e)})

    # 4) Field validation — collect ALL errors.
    errs = FieldErrors()
    email_pair = validate_email_field(req.email, errs)
    username_pair = validate_username_field(req.username, errs)
    uname = username_pair[0] if username_pair else ""
    email_for_pw = email_pair[0] if email_pair else ""
    password = validate_password_field(req.password, username=uname, email=email_for_pw, errs=errs)
    display_name = validate_display_name_field(req.display_name, errs)

    if errs:
        return JSONResponse(status_code=status.HTTP_422_UNPROCESSABLE_ENTITY,
            content={"status": "error", "message": "Validation failed.", "errors": errs.as_list()})

    email_display, email_canonical = email_pair
    username_display, username_lower = username_pair
    if not display_name:
        display_name = username_display

    # 5) Hash (constant heavy work regardless of duplicate status).
    try:
        pw_hash = _ph.hash(password)
    except HashingError:
        return JSONResponse(status_code=status.HTTP_500_INTERNAL_SERVER_ERROR,
            content={"status": "error", "message": "Internal error. Please try again."})

    # 6) Insert. DB UNIQUE resolves concurrent/duplicate signups atomically.
    created = insert_user(
        email=email_display, email_canonical=email_canonical,
        username=username_display, username_lower=username_lower,
        display_name=display_name, password_hash=pw_hash, created_at=time.time())

    if not created:
        # Timing equalizer so the duplicate path isn't observably faster.
        try:
            _ph.verify(_DUMMY_HASH, "argon2-timing-equalizer-placeholder")
        except Exception:
            pass
        hmac.compare_digest(email_canonical, email_canonical)

    # Identical 201 + body in both branches → caller can't tell new vs existing.
    return JSONResponse(status_code=status.HTTP_201_CREATED, content=_NEUTRAL_SUCCESS)
