    "qwerty", "qwerty123", "admin", "admin123", "letmein", "welcome",
    "welcome1", "iloveyou", "monkey", "dragon", "football", "baseball",
    "abc123", "111111", "000000", "passw0rd", "p@ssw0rd",
    "correcthorsebatterystaple", "changeme", "default", "secret",
}

KEYBOARD_SEQUENCES = [
    "abcdefghijklmnopqrstuvwxyz",
    "qwertyuiop",
    "asdfghjkl",
    "zxcvbnm",
    "0123456789",
]

LEET_TRANS = str.maketrans({
    "0": "o", "1": "i", "3": "e", "4": "a", "5": "s",
    "7": "t", "@": "a", "$": "s", "!": "i",
})


class SlidingWindowRateLimiter:
    def __init__(self) -> None:
        self._hits: dict[str, deque[float]] = defaultdict(deque)
        self._lock = threading.Lock()

    def hit(self, key: str, limit: int, window_seconds: int) -> tuple[bool, int]:
        now = time.monotonic()
        with self._lock:
            bucket = self._hits[key]
            cutoff = now - window_seconds
            while bucket and bucket[0] <= cutoff:
                bucket.popleft()

            if len(bucket) >= limit:
                retry_after = max(1, int(window_seconds - (now - bucket[0])))
                return False, retry_after

            bucket.append(now)
            return True, 0


RATE_LIMITER = SlidingWindowRateLimiter()
HIBP_CACHE: dict[str, set[str]] = {}
HIBP_LOCK = threading.Lock()


def add_error(errors: list[dict[str, str]], field: str, code: str, message: str) -> None:
    errors.append({"field": field, "code": code, "message": message})


def error_response(
    request: Request,
    status_code: int,
    errors: list[dict[str, str]],
    headers: dict[str, str] | None = None,
) -> JSONResponse:
    return JSONResponse(
        status_code=status_code,
        content={
            "ok": False,
            "request_id": getattr(request.state, "request_id", secrets.token_urlsafe(16)),
            "errors": errors,
        },
        headers=headers,
    )


def accepted_response(request: Request) -> JSONResponse:
    return JSONResponse(
        status_code=202,
        content={
            "ok": True,
            "request_id": getattr(request.state, "request_id", secrets.token_urlsafe(16)),
            "message": "If registration can be completed, you will receive the next steps.",
        },
    )


def add_security_headers(response: JSONResponse, request_id: str) -> JSONResponse:
    headers = {
        "X-Request-ID": request_id,
        "Cache-Control": "no-store",
        "Pragma": "no-cache",
        "X-Content-Type-Options": "nosniff",
        "X-Frame-Options": "DENY",
        "Referrer-Policy": "no-referrer",
        "Content-Security-Policy": "default-src 'none'; frame-ancestors 'none'; base-uri 'none'",
    }
    for key, value in headers.items():
        if key not in response.headers:
            response.headers[key] = value
    return response


@app.middleware("http")
async def hardening_middleware(request: Request, call_next):
    request.state.request_id = secrets.token_urlsafe(16)

    content_length = request.headers.get("content-length")
    if content_length:
        try:
            if int(content_length) > MAX_BODY_BYTES:
                response = error_response(
                    request,
                    413,
                    [{"field": "body", "code": "too_large", "message": "Request body is too large."}],
                )
                return add_security_headers(response, request.state.request_id)
        except ValueError:
            response = error_response(
                request,
                400,
                [{"field": "body", "code": "invalid_content_length", "message": "Invalid Content-Length header."}],
            )
            return add_security_headers(response, request.state.request_id)

    response = await call_next(request)
    return add_security_headers(response, request.state.request_id)


def now_iso() -> str:
    return datetime.now(timezone.utc).isoformat(timespec="seconds")


def keyed_fingerprint(value: str) -> str:
    data = str(value)[:512].encode("utf-8", "replace")
    return hmac.new(RATE_LIMIT_SECRET.encode(), data, hashlib.sha256).hexdigest()


def constant_time_text_equal(a: str, b: str) -> bool:
    left = hashlib.sha256(str(a).encode("utf-8", "replace")).digest()
    right = hashlib.sha256(str(b).encode("utf-8", "replace")).digest()
    return hmac.compare_digest(left, right)


def constant_time_any(value: str, candidates: set[str]) -> bool:
    matched = False
    for candidate in candidates:
        matched = matched or constant_time_text_equal(value, candidate)
    return matched


def content_key(value: str) -> str:
    value = unicodedata.normalize("NFKC", value).casefold().translate(LEET_TRANS)
    value = unicodedata.normalize("NFKD", value)
    value = "".join(ch for ch in value if not unicodedata.combining(ch))
    return re.sub(r"[^a-z0-9]+", "", value)


RESERVED_CONTENT_KEYS = {content_key(value) for value in RESERVED_USERNAMES}
COMMON_PASSWORD_KEYS = {content_key(value) for value in COMMON_PASSWORDS}


def contains_forbidden_unicode(value: str) -> bool:
    for ch in value:
        if ch in BIDI_CONTROLS or ch in ZERO_WIDTH:
            return True
        if unicodedata.category(ch).startswith("C"):
            return True
    return False


def script_name(ch: str) -> str | None:
    if not ch.isalpha():
        return None
    name = unicodedata.name(ch, "")
    for script in ("LATIN", "CYRILLIC", "GREEK", "HEBREW", "ARABIC", "DEVANAGARI", "HIRAGANA", "KATAKANA", "HANGUL", "CJK"):
        if script in name:
            return script
    return "OTHER"


def has_dangerous_mixed_scripts(value: str) -> bool:
    scripts = {script_name(ch) for ch in value if script_name(ch)}
    return "LATIN" in scripts and bool({"CYRILLIC", "GREEK"} & scripts)


def client_ip(request: Request) -> str:
    if TRUST_PROXY:
        forwarded_for = request.headers.get("x-forwarded-for", "")
        if forwarded_for:
            return forwarded_for.split(",", 1)[0].strip()
    return request.client.host if request.client else "unknown"


def enforce_rate_limits(
    request: Request,
    scope: str,
    identity: str,
    rules: list[tuple[int, int]],
) -> JSONResponse | None:
    base_key = f"{scope}:{keyed_fingerprint(identity)}"
    for limit, window_seconds in rules:
        allowed, retry_after = RATE_LIMITER.hit(f"{base_key}:{limit}:{window_seconds}", limit, window_seconds)
        if not allowed:
            return error_response(
                request,
                429,
                [{"field": "global", "code": "rate_limited", "message": "Too many registration attempts. Try later."}],
                headers={"Retry-After": str(retry_after)},
            )
    return None


def origin_from_url(value: str) -> str:
    try:
        parsed = urlsplit(value)
    except ValueError:
        return ""
    if not parsed.scheme or not parsed.netloc:
        return ""
    return f"{parsed.scheme}://{parsed.netloc}".rstrip("/")


def csrf_or_origin_error(request: Request) -> JSONResponse | None:
    origin = request.headers.get("origin")
    if origin and TRUSTED_ORIGINS and origin.rstrip("/") not in TRUSTED_ORIGINS:
        return error_response(
            request,
            403,
            [{"field": "global", "code": "bad_origin", "message": "Request origin is not allowed."}],
        )

    referer = request.headers.get("referer")
    if not origin and referer and TRUSTED_ORIGINS:
        referer_origin = origin_from_url(referer)
        if referer_origin not in TRUSTED_ORIGINS:
            return error_response(
                request,
                403,
                [{"field": "global", "code": "bad_referer", "message": "Request referer is not allowed."}],
            )

    if request.headers.get("cookie") and REQUIRE_CSRF_FOR_COOKIE_REQUESTS:
        csrf_cookie = request.cookies.get("csrf_token", "")
        csrf_header = request.headers.get("x-csrf-token", "")
        if not csrf_cookie or not csrf_header or not constant_time_text_equal(csrf_cookie, csrf_header):
            return error_response(
                request,
                403,
                [{"field": "global", "code": "csrf_failed", "message": "CSRF validation failed."}],
            )

    return None


async def read_limited_json(request: Request) -> tuple[dict[str, Any] | None, JSONResponse | None]:
    content_type = request.headers.get("content-type", "").split(";", 1)[0].strip().lower()
    if content_type != "application/json":
        return None, error_response(
            request,
            415,
            [{"field": "body", "code": "unsupported_media_type", "message": "Content-Type must be application/json."}],
        )

    body = await request.body()
    if not body:
        return None, error_response(
            request,
            400,
            [{"field": "body", "code": "empty", "message": "Request body is required."}],
        )
    if len(body) > MAX_BODY_BYTES:
        return None, error_response(
            request,
            413,
            [{"field": "body", "code": "too_large", "message": "Request body is too large."}],
        )

    try:
        payload = json.loads(body)
    except json.JSONDecodeError:
        return None, error_response(
            request,
            400,
            [{"field": "body", "code": "malformed_json", "message": "Request body must be valid JSON."}],
        )

    if not isinstance(payload, dict):
        return None, error_response(
            request,
            422,
            [{"field": "body", "code": "invalid_type", "message": "Request body must be a JSON object."}],
        )

    return payload, None


def domain_matches(domain: str, blocked: set[str]) -> bool:
    return any(domain == item or domain.endswith("." + item) for item in blocked)


def to_ascii_domain(domain: str) -> str:
    domain = unicodedata.normalize("NFC", domain)
    if idna is not None:
        return idna.encode(domain, uts46=True, std3_rules=True).decode("ascii").lower()
    return domain.encode("idna").decode("ascii").lower()


def domain_has_dns_records(domain: str) -> bool | None:
    try:
        import dns.exception
        import dns.resolver
    except Exception:
        return None

    resolver = dns.resolver.Resolver()
    resolver.timeout = 1.0
    resolver.lifetime = 2.0

    try:
        if list(resolver.resolve(domain, "MX")):
            return True
    except Exception:
        pass

    for record_type in ("A", "AAAA"):
        try:
            answers = resolver.resolve(domain, record_type)
            for answer in answers:
                ip = ipaddress.ip_address(answer.to_text())
                if not (ip.is_private or ip.is_loopback or ip.is_link_local or ip.is_reserved or ip.is_multicast):
                    return True
        except Exception:
            continue

    return False


def normalize_email(raw: Any, errors: list[dict[str, str]]) -> dict[str, str] | None:
    field = "email"
    start_count = len(errors)

    if not isinstance(raw, str):
        add_error(errors, field, "invalid_type", "Email must be a string.")
        return None

    if raw != raw.strip():
        add_error(errors, field, "outer_whitespace", "Email must not start or end with whitespace.")

    value = unicodedata.normalize("NFKC", raw.strip())

    if not value:
        add_error(errors, field, "required", "Email is required.")
    if len(value) > 254:
        add_error(errors, field, "too_long", "Email must be 254 characters or fewer.")
    if len(value.encode("utf-8", "replace")) > 320:
        add_error(errors, field, "too_many_bytes", "Email is too large.")
    if contains_forbidden_unicode(value):
        add_error(errors, field, "unsafe_unicode", "Email contains control or invisible characters.")
    if any(ch.isspace() for ch in value):
        add_error(errors, field, "whitespace", "Email must not contain whitespace.")
    if value.count("@") != 1:
        add_error(errors, field, "invalid_format", "Email must contain exactly one @ symbol.")
        return None

    local, domain = value.rsplit("@", 1)

    if not local:
        add_error(errors, field, "missing_local_part", "Email local part is required.")
    if not domain:
        add_error(errors, field, "missing_domain", "Email domain is required.")
    if len(local) > 64:
        add_error(errors, field, "local_too_long", "Email local part must be 64 characters or fewer.")
    if not ASCII_RE.fullmatch(local):
        add_error(errors, field, "smtp_utf8_not_supported", "Email local part must use ASCII characters.")
    if local.startswith(".") or local.endswith(".") or ".." in local:
        add_error(errors, field, "invalid_dots", "Email local part has invalid dot placement.")
    if local and not EMAIL_LOCAL_RE.fullmatch(local):
        add_error(errors, field, "invalid_local_part", "Email local part contains invalid characters.")
    if domain.startswith("[") or domain.endswith("]"):
        add_error(errors, field, "ip_literal_not_allowed", "Email domain must not be an IP literal.")
    if domain.endswith("."):
        add_error(errors, field, "trailing_domain_dot", "Email domain must not end with a dot.")

    try:
        ascii_domain = to_ascii_domain(domain)
    except Exception:
        add_error(errors, field, "invalid_idn", "Email domain is not a valid internationalized domain name.")
        return None

    if len(ascii_domain) > 253:
        add_error(errors, field, "domain_too_long", "Email domain must be 253 characters or fewer.")
    if "_" in ascii_domain:
        add_error(errors, field, "domain_underscore", "Email domain must not contain underscores.")
    if ".." in ascii_domain:
        add_error(errors, field, "domain_empty_label", "Email domain contains an empty label.")

    labels = ascii_domain.split(".")
    if len(labels) < 2:
        add_error(errors, field, "domain_requires_tld", "Email domain must include a public suffix.")

    for label in labels:
        if not label:
            continue
        if len(label) > 63:
            add_error(errors, field, "domain_label_too_long", "Email domain labels must be 63 characters or fewer.")
        if label.startswith("-") or label.endswith("-"):
            add_error(errors, field, "domain_label_hyphen", "Email domain labels must not start or end with hyphen.")
        if not re.fullmatch(r"[a-z0-9-]+", label):
            add_error(errors, field, "domain_label_chars", "Email domain contains invalid characters.")

    tld = labels[-1] if labels else ""
    if tld in RESERVED_TLDS:
        add_error(errors, field, "reserved_domain", "Email domain uses a reserved or private suffix.")
    if tld.isdigit():
        add_error(errors, field, "numeric_tld", "Email top-level domain must not be numeric.")
    if tld and not re.fullmatch(r"(?:[a-z]{2,63}|xn--[a-z0-9-]{2,59})", tld):
        add_error(errors, field, "invalid_tld", "Email top-level domain is invalid.")

    try:
        ipaddress.ip_address(ascii_domain)
        add_error(errors, field, "ip_domain_not_allowed", "Email domain must not be an IP address.")
    except ValueError:
        pass

    if domain_matches(ascii_domain, DISPOSABLE_DOMAINS):
        add_error(errors, field, "disposable_domain", "Disposable email domains are not allowed.")

    if len(errors) == start_count and REQUIRE_EMAIL_DNS_CHECK:
        dns_ok = domain_has_dns_records(ascii_domain)
        if dns_ok is not True:
            add_error(errors, field, "domain_unreachable", "Email domain could not be verified.")

    if len(errors) != start_count:
        return None

    normalized_local = local.lower()
    return {
        "email": f"{normalized_local}@{ascii_domain}",
        "email_local": normalized_local,
        "email_domain_ascii": ascii_domain,
    }


def normalize_username(raw: Any, errors: list[dict[str, str]]) -> str | None:
    field = "username"
    start_count = len(errors)

    if not isinstance(raw, str):
        add_error(errors, field, "invalid_type", "Username must be a string.")
        return None

    if raw != raw.strip():
        add_error(errors, field, "outer_whitespace", "Username must not start or end with whitespace.")

    value = unicodedata.normalize("NFKC", raw.strip()).casefold()

    if not value:
        add_error(errors, field, "required", "Username is required.")
    if len(value) < 3:
        add_error(errors, field, "too_short", "Username must be at least 3 characters.")
    if len(value) > 30:
        add_error(errors, field, "too_long", "Username must be 30 characters or fewer.")
    if not ASCII_RE.fullmatch(value):
        add_error(errors, field, "ascii_only", "Username must use ASCII characters only.")
    if contains_forbidden_unicode(raw):
        add_error(errors, field, "unsafe_unicode", "Username contains control or invisible characters.")
    if "@" in value:
        add_error(errors, field, "looks_like_email", "Username must not be an email address.")
    if not USERNAME_RE.fullmatch(value):
        add_error(errors, field, "invalid_characters", "Username may contain only letters, numbers, dots, hyphens, and underscores.")
    if re.search(r"[._-]{2,}", value):
        add_error(errors, field, "repeated_separator", "Username must not contain repeated separators.")
    if value.startswith("xn--"):
        add_error(errors, field, "punycode_prefix", "Username must not use punycode-style prefixes.")

    key = content_key(value)
    if value in RESERVED_USERNAMES or key in RESERVED_CONTENT_KEYS:
        add_error(errors, field, "reserved", "Username is reserved.")
    if any(bad in key for bad in OFFENSIVE_SUBSTRINGS):
        add_error(errors, field, "offensive", "Username is not allowed.")
    if re.fullmatch(r"[0-9a-f]{8}-?[0-9a-f]{4}-?[0-9a-f]{4}-?[0-9a-f]{4}-?[0-9a-f]{12}", value):
        add_error(errors, field, "uuid_like", "Username must not look like an internal identifier.")

    return None if len(errors) != start_count else value


def normalize_display_name(raw: Any, errors: list[dict[str, str]]) -> dict[str, str] | None:
    field = "display_name"
    start_count = len(errors)

    if not isinstance(raw, str):
        add_error(errors, field, "invalid_type", "Display name must be a string.")
        return None

    if raw != raw.strip():
        add_error(errors, field, "outer_whitespace", "Display name must not start or end with whitespace.")

    value = re.sub(r"\s+", " ", unicodedata.normalize("NFKC", raw.strip()))

    if not value:
        add_error(errors, field, "required", "Display name is required.")
    if len(value) > 80:
        add_error(errors, field, "too_long", "Display name must be 80 characters or fewer.")
    if len(value.encode("utf-8", "replace")) > 160:
        add_error(errors, field, "too_many_bytes", "Display name is too large.")
    if contains_forbidden_unicode(raw):
        add_error(errors, field, "unsafe_unicode", "Display name contains control or invisible characters.")
    if has_dangerous_mixed_scripts(value):
        add_error(errors, field, "mixed_scripts", "Display name mixes visually confusable scripts.")
    if not any(ch.isalnum() for ch in value):
        add_error(errors, field, "no_letters_or_numbers", "Display name must contain letters or numbers.")
    if re.search(r"https?://|www\.|@", value, re.IGNORECASE):
        add_error(errors, field, "contact_or_url", "Display name must not contain URLs or contact information.")
    if re.search(r"[<>]", value):
        add_error(errors, field, "unsafe_html", "Display name must not contain HTML-sensitive angle brackets.")

    key = content_key(value)
    if key in RESERVED_CONTENT_KEYS:
        add_error(errors, field, "reserved", "Display name is reserved.")
    if any(bad in key for bad in OFFENSIVE_SUBSTRINGS):
        add_error(errors, field, "offensive", "Display name is not allowed.")

    if len(errors) != start_count:
        return None

    return {
        "display_name": html.escape(value, quote=True),
        "display_name_search": content_key(value),
        "display_name_plain": value,
    }


def estimate_entropy_bits(password: str) -> float:
    pool = 0
    if any(ch.islower() for ch in password):
        pool += 26
    if any(ch.isupper() for ch in password):
        pool += 26
    if any(ch.isdigit() for ch in password):
        pool += 10
    if any((not ch.isalnum()) and ord(ch) < 128 for ch in password):
        pool += 33
    if any(ord(ch) >= 128 for ch in password):
        pool += 50

    pool = max(pool, 1)
    entropy = len(password) * math.log2(pool)

    if re.search(r"(.)\1{2,}", password, re.DOTALL):
        entropy -= 12
    if has_keyboard_sequence(password):
        entropy -= 15
    if content_key(password) in COMMON_PASSWORD_KEYS:
        entropy = 0

    return max(entropy, 0)


def has_keyboard_sequence(password: str) -> bool:
    key = content_key(password)
    for sequence in KEYBOARD_SEQUENCES:
        for i in range(0, len(sequence) - 3):
            part = sequence[i:i + 4]
            if part in key or part[::-1] in key:
                return True
    return False


def password_seen_in_breach(password: str) -> bool | None:
    if not HIBP_ENABLED or requests is None:
        return None

    digest = hashlib.sha1(password.encode("utf-8", "replace")).hexdigest().upper()
    prefix, suffix = digest[:5], digest[5:]

    with HIBP_LOCK:
        cached = HIBP_CACHE.get(prefix)
    if cached is None:
        try:
            response = requests.get(
                f"https://api.pwnedpasswords.com/range/{prefix}",
                headers={
                    "User-Agent": "secure-registration-example",
                    "Add-Padding": "true",
                },
                timeout=2.0,
            )
            if response.status_code != 200:
                return None
            cached = {line.split(":", 1)[0].strip().upper() for line in response.text.splitlines() if ":" in line}
            with HIBP_LOCK:
                HIBP_CACHE[prefix] = cached
        except Exception:
            return None

    return suffix in cached


def validate_password(
    raw: Any,
    username: str | None,
    email_info: dict[str, str] | None,
    display_info: dict[str, str] | None,
    errors: list[dict[str, str]],
) -> None:
    field = "password"

    if not isinstance(raw, str):
        add_error(errors, field, "invalid_type", "Password must be a string.")
        return

    if len(raw) < MIN_PASSWORD_LENGTH:
        add_error(errors, field, "too_short", f"Password must be at least {MIN_PASSWORD_LENGTH} characters.")
    if len(raw) > MAX_PASSWORD_LENGTH:
        add_error(errors, field, "too_long", f"Password must be {MAX_PASSWORD_LENGTH} characters or fewer.")
    if len(raw.encode("utf-8", "replace")) > MAX_PASSWORD_BYTES:
        add_error(errors, field, "too_many_bytes", "Password is too large to process safely.")
    if raw != raw.strip():
        add_error(errors, field, "outer_whitespace", "Password must not start or end with whitespace.")
    if contains_forbidden_unicode(raw):
        add_error(errors, field, "unsafe_unicode", "Password contains control or invisible characters.")

    categories = {
        "lowercase": any(ch.islower() for ch in raw),
        "uppercase": any(ch.isupper() for ch in raw),
        "digit": any(ch.isdigit() for ch in raw),
        "symbol": any((not ch.isalnum()) and not ch.isspace() for ch in raw),
    }
    if sum(categories.values()) < 3:
        add_error(errors, field, "character_variety", "Password must use at least three character classes.")
    for name, present in categories.items():
        if not present:
            add_error(errors, field, f"missing_{name}", f"Password must include at least one {name} character.")

    key = content_key(raw)
    if constant_time_any(raw.casefold(), {item.casefold() for item in COMMON_PASSWORDS}) or key in COMMON_PASSWORD_KEYS:
        add_error(errors, field, "common_password", "Password is too common.")
    if re.search(r"(.)\1{3,}", raw, re.DOTALL):
        add_error(errors, field, "repeated_characters", "Password must not contain long repeated character runs.")
    if has_keyboard_sequence(raw):
        add_error(errors, field, "sequential_characters", "Password must not contain keyboard or numeric sequences.")
    if estimate_entropy_bits(raw) < 50:
        add_error(errors, field, "low_entropy", "Password is not complex enough.")

    personal_tokens: list[tuple[str, str]] = []
    if username:
        personal_tokens.append(("username", username))
    if email_info:
        personal_tokens.extend([
            ("email", email_info["email"]),
            ("email local part", email_info["email_local"]),
            ("email domain", email_info["email_domain_ascii"].split(".", 1)[0]),
        ])
    if display_info:
        personal_tokens.append(("display name", display_info["display_name_plain"]))

    similar_to_personal = False
    for label, token in personal_tokens:
        token_key = content_key(token)
        if len(token_key) < 4:
            continue
        if token_key in key or constant_time_text_equal(key, token_key):
            similar_to_personal = True
        if SequenceMatcher(None, key, token_key).ratio() >= 0.72:
            similar_to_personal = True
    if similar_to_personal:
        add_error(errors, field, "similar_to_personal_info", "Password must not contain or closely match account identifiers.")

    if len(raw) <= MAX_PASSWORD_LENGTH and len(raw.encode("utf-8", "replace")) <= MAX_PASSWORD_BYTES:
        breached = password_seen_in_breach(raw)
        if breached is True:
            add_error(errors, field, "breached", "Password has appeared in a known breach.")
        elif breached is None and HIBP_FAIL_CLOSED:
            add_error(errors, field, "breach_check_unavailable", "Password breach check is temporarily unavailable.")


def validate_registration_payload(payload: dict[str, Any]) -> tuple[dict[str, str], list[dict[str, str]]]:
    errors: list[dict[str, str]] = []
    required = {"email", "username", "password", "display_name"}

    for field in sorted(set(payload) - required):
        add_error(errors, field, "unknown_field", "Unknown fields are not allowed.")
    for field in sorted(required):
        if field not in payload:
            add_error(errors, field, "required", f"{field} is required.")
        elif payload[field] is None:
            add_error(errors, field, "null", f"{field} must not be null.")

    email_info = normalize_email(payload.get("email"), errors) if payload.get("email") is not None else None
    username = normalize_username(payload.get("username"), errors) if payload.get("username") is not None else None
    display_info = normalize_display_name(payload.get("display_name"), errors) if payload.get("display_name") is not None else None

    if payload.get("password") is not None:
        validate_password(payload.get("password"), username, email_info, display_info, errors)

    normalized: dict[str, str] = {}
    if email_info:
        normalized.update(email_info)
    if username:
        normalized["username"] = username
        normalized["username_canonical"] = username
    if display_info:
        normalized.update(display_info)

    return normalized, errors


def init_db() -> None:
    conn = sqlite3.connect(DB_PATH, timeout=10)
    try:
        conn.execute("PRAGMA journal_mode=WAL")
        conn.execute("PRAGMA foreign_keys=ON")
        conn.execute("""
            CREATE TABLE IF NOT EXISTS users (
                id TEXT PRIMARY KEY,
                email TEXT NOT NULL UNIQUE,
                email_domain_ascii TEXT NOT NULL,
                username TEXT NOT NULL,
                username_canonical TEXT NOT NULL UNIQUE,
                password_hash TEXT NOT NULL,
                display_name TEXT NOT NULL,
                display_name_search TEXT NOT NULL,
                status TEXT NOT NULL DEFAULT 'pending_verification',
                created_at TEXT NOT NULL,
                updated_at TEXT NOT NULL,
                CHECK(length(email) <= 254),
                CHECK(length(username_canonical) BETWEEN 3 AND 30),
                CHECK(substr(password_hash, 1, 10) = '$argon2id$'),
                CHECK(status IN ('pending_verification', 'active', 'disabled'))
            )
        """)
        conn.execute("CREATE UNIQUE INDEX IF NOT EXISTS idx_users_email ON users(email)")
        conn.execute("CREATE UNIQUE INDEX IF NOT EXISTS idx_users_username ON users(username_canonical)")
        conn.commit()
    finally:
        conn.close()


@app.on_event("startup")
def startup() -> None:
    init_db()


def insert_user(row: dict[str, str]) -> bool:
    conn = sqlite3.connect(DB_PATH, timeout=10, isolation_level=None)
    try:
        conn.execute("PRAGMA foreign_keys=ON")
        conn.execute("PRAGMA busy_timeout=5000")
        conn.execute("BEGIN IMMEDIATE")
        conn.execute(
            """
            INSERT INTO users (
                id, email, email_domain_ascii, username, username_canonical,
                password_hash, display_name, display_name_search, status,
                created_at, updated_at
            )
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            """,
            (
                row["id"],
                row["email"],
                row["email_domain_ascii"],
                row["username"],
                row["username_canonical"],
                row["password_hash"],
                row["display_name"],
                row["display_name_search"],
                "pending_verification",
                row["created_at"],
                row["updated_at"],
            ),
        )
        conn.commit()
        return True
    except sqlite3.IntegrityError:
        conn.rollback()
        return False
    except Exception:
        conn.rollback()
        raise
    finally:
        conn.close()


async def uniform_valid_response_delay(started_at: float) -> None:
    floor = 0.45 + secrets.randbelow(150) / 1000
    elapsed = time.monotonic() - started_at
    if elapsed < floor:
        await asyncio.sleep(floor - elapsed)


@app.post("/api/register")
async def register(request: Request):
    started_at = time.monotonic()

    csrf_error = csrf_or_origin_error(request)
    if csrf_error:
        return csrf_error

    limited = enforce_rate_limits(
        request,
        "register-ip",
        client_ip(request),
        [(8, 60), (30, 3600), (120, 86400)],
    )
    if limited:
        return limited

    payload, parse_error = await read_limited_json(request)
    if parse_error:
        return parse_error

    identifier = str(payload.get("email") or payload.get("username") or client_ip(request))
    limited = enforce_rate_limits(
        request,
        "register-identifier",
        identifier.casefold(),
        [(5, 300), (12, 3600), (30, 86400)],
    )
    if limited:
        return limited

    normalized, validation_errors = validate_registration_payload(payload)
    if validation_errors:
        return error_response(request, 422, validation_errors)

    password_hash = PASSWORD_HASHER.hash(payload["password"])
    now = now_iso()
    row = {
        **normalized,
        "id": str(uuid.uuid4()),
        "password_hash": password_hash,
        "created_at": now,
        "updated_at": now,
    }

    try:
        # All user-controlled values are passed via placeholders in insert_user.
        # Unique constraint conflicts intentionally receive the same response as success.
        await run_in_threadpool(insert_user, row)
    except sqlite3.Error:
        return error_response(
            request,
            500,
            [{"field": "global", "code": "server_error", "message": "Registration is temporarily unavailable."}],
        )

    await uniform_valid_response_delay(started_at)
    return accepted_response(request)


if __name__ == "__main__":
    import uvicorn

    init_db()
    uvicorn.run(app, host="127.0.0.1", port=8000)
